1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { processScenario } from "./claim-office.js";
4	
5	describe("Claim Office", () => {
6	  describe("quote: base premiums", () => {
7	    it("should return premium 5 for an empty item list (only processing fee)", () => {
8	      const result = processScenario({
9	        customer: { yearsWithMHPCO: 0 },
10	        steps: [{ op: "quote", items: [] }],
11	      });
12	
13	      expect(result).toEqual({ results: [{ premium: 5 }] });
14	    });
15	    it.todo(
16	      "should quote a single sword for a newcomer at 115 (100 base + 10% first insurance + 5 fee)"
17	    );
18	    it.todo(
19	      "should quote a single amulet for a newcomer at 71 (60 base + 10% first insurance + 5 fee)"
20	    );
21	    it.todo(
22	      "should quote a single staff for a newcomer at 93 (80 base + 10% first insurance + 5 fee)"
23	    );
24	    it.todo(
25	      "should quote a single potion for a newcomer at 49 (40 base + 10% first insurance + 5 fee)"
26	    );
27	    it.todo("should charge 25 base premium per component (2 runes → base premium 50)");
28	  });
29	
30	  describe("quote: building block of 3 alike components", () => {
31	    it.todo("should price a block of exactly 3 runes at base premium 60");
32	    it.todo("should not apply the block to 4 runes (base premium 100 — block requires exactly 3)");
33	    it.todo("should not apply the block to 7 runes (base premium 175)");
34	    it.todo(
35	      "should not form a block from different component types (2 runes + 1 moonstone → base premium 75)"
36	    );
37	    it.todo(
38	      "should form two separate blocks for 3 runes + 3 moonstones (base premium 120)"
39	    );
40	  });
41	
42	  describe("quote: item-level modifiers", () => {
43	    it.todo("should add 50% curse surcharge to a cursed item's base premium");
44	    it.todo("should add 30% high-enchantment surcharge for enchantment exactly 5");
45	    it.todo("should not add the high-enchantment surcharge for enchantment 4");
46	    it.todo("should stack curse and high-enchantment surcharges on the same item");
47	    it.todo(
48	      "should apply the curse surcharge only to the cursed item's base premium, not the whole policy (cursed sword + plain amulet → policy base 210 before policy modifiers and fee)"
49	    );
50	  });
51	
52	  describe("quote: policy-level modifiers", () => {
53	    it.todo("should apply the 20% loyalty discount for a customer with exactly 2 years with MHPCO");
54	    it.todo("should not apply the loyalty discount for a customer with fewer than 2 years");
55	    it.todo("should apply the 15% follow-up discount on the customer's second quote in the scenario");
56	    it.todo(
57	      "should quote a newcomer's cursed steel sword (enchantment 3) at 165 (100 + 50 curse + 10 first insurance + 5 fee)"
58	    );
59	    it.todo(
60	      "should quote a 3-year customer's second quote for a cursed sword (enchantment 7) at 160 (100 + 50 + 30 − 20 loyalty + 10 first − 15 follow-up + 5 fee)"
61	    );
62	  });
63	
64	  describe("quote: rounding", () => {
65	    it.todo(
66	      "should round the final premium up to a whole G, keeping intermediates fractional (7 runes for a newcomer: 175 × 1.10 + 5 = 197.5 → 198)"
67	    );
68	  });
69	
70	  describe("quote: errors", () => {
71	    it.todo("should throw an error for an unknown item type (e.g. broomstick)");
72	  });
73	
74	  describe("claim: standard reimbursement", () => {
75	    it.todo(
76	      "should pay damage minus 100 deductible for a regular item (steel sword enchantment 3, damage 500 → payout 400)"
77	    );
78	    it.todo(
79	      "should pay damage minus 100 deductible for a component (rune, damage 200 → payout 100)"
80	    );
81	    it.todo("should include payout and remainingCap in a claim result");
82	  });
83	
84	  describe("claim: special reimbursement clauses", () => {
85	    it.todo(
86	      "should reimburse 50% for enchantment ≥ 8 before deductible (steel sword enchantment 9, damage 1000 → payout 400)"
87	    );
88	    it.todo(
89	      "should fully reimburse dragon-material items before deductible (dragon sword enchantment 5, damage 800 → payout 700)"
90	    );
91	    it.todo(
92	      "should let the 50% rule win when both clauses apply (dragon sword enchantment 9, damage 1000 → payout 400)"
93	    );
94	    it.todo(
95	      "should apply the 50% rule at exactly enchantment 8 (dragon sword enchantment 8, damage 1000 → payout 400)"
96	    );
97	  });
98	
99	  describe("claim: multiple damages in one incident", () => {
100	    it.todo(
101	      "should apply the deductible once per damaged item (sword 500 + amulet 300 → payout 600)"
102	    );
103	    it.todo(
104	      "should treat two damage entries for two insured swords as separate damages with their own deductibles"
105	    );
106	  });
107	
108	  describe("claim: payout cap", () => {
109	    it.todo("should cap the payout at twice the insurance sum (single sword → cap 2000)");
110	    it.todo(
111	      "should compute the insurance sum from item values for multiple items (sword + amulet → insurance sum 1600, cap 3200)"
112	    );
113	    it.todo("should compute the cap for two swords (insurance sum 2000, cap 4000)");
114	    it.todo(
115	      "should not let premium modifiers change the cap (cursed sword → cap still 2000)"
116	    );
117	    it.todo(
118	      "should not let the block discount affect the insurance sum (sword + 3 runes → insurance sum 1750)"
119	    );
120	    it.todo(
121	      "should deplete the cap across successive claims (sword, two claims of 1500: first payout 1400 / remainingCap 600, second payout 600 / remainingCap 0)"
122	    );
123	  });
124	
125	  describe("claim: rounding", () => {
126	    it.todo("should round the final payout down to a whole G");
127	  });
128	
129	  describe("claim: errors", () => {
130	    it.todo("should throw an error for a damage entry whose item type is not in the policy");
131	    it.todo("should throw an error for a damage entry with an unknown item type");
132	    it.todo(
133	      "should throw an error when damages contain more entries of a type than insured items of that type"
134	    );
135	    it.todo("should throw an error for a negative damage amount");
136	  });
137	
138	  describe("scenario processing", () => {
139	    it.todo(
140	      "should return one result per step in input order (quote → {premium}, claim → {payout, remainingCap})"
141	    );
142	  });
143	});
